<?php namespace GitFlowOrchestrator\GitHub; use Psr\Http\Client\ClientInterface; use Psr\Http\Message\RequestFactoryInterface; use Psr\Http\Message\ResponseInterface; use RuntimeException; class Client { private ClientInterface $httpClient; private RequestFactoryInterface $requestFactory; private string $apiToken; private string $baseUrl = "https://api.github.com"; public function __construct(ClientInterface $httpClient, RequestFactoryInterface $requestFactory, string $apiToken) { $this->httpClient = $httpClient; $this->requestFactory = $requestFactory; $this->apiToken = $apiToken; } public function send(string $method, string $endpoint, array $payload = []): array { $request = $this->requestFactory->createRequest($method, $this->baseUrl . $endpoint) ->withHeader("Authorization", "Bearer " . $this->apiToken) ->withHeader("Accept", "application/vnd.github.v3+json"); if (!empty($payload)) { $request = $request->withBody($this->createStream(json_encode($payload))) ->withHeader("Content-Type", "application/json"); } try { $response = $this->httpClient->sendRequest($request); return $this->handleResponse($response); } catch (\Exception $e) { throw new RuntimeException("GitHub API Request Failed: " . $e->getMessage(), 0, $e); } } private function handleResponse(ResponseInterface $response): array { $statusCode = $response->getStatusCode(); $body = json_decode((string)$response->getBody(), true); if ($statusCode >= 400) { throw new RuntimeException("GitHub API Error: " . ($body['message'] ?? "Unknown error"), $statusCode); } return $body ?? []; } private function createStream(string $content) { $stream = fopen("php://temp", "r+"); fwrite($stream, $content); rewind($stream); return new \GuzzleHttp\Psr7\Stream($stream); } }